class Person {
    String name;
    int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
        System.out.println("Person constructor called");
    }

    void introduce() {
        System.out.println("Hi, I'm " + name + ". I'm " + age + " years old.");
    }
}

class Student extends Person {
    String studentId;
    String major;

    Student(String name, int age, String studentId, String major) {
        super(name, age);  // Calls parent constructor FIRST
        this.studentId = studentId;
        this.major = major;
        System.out.println("Student constructor called");
    }

    @Override
    void introduce() {
        super.introduce();  // Call parent's version
        System.out.println("My student ID is " + studentId);
        System.out.println("I'm majoring in " + major);
    }
}

public class SuperExample {
    public static void main(String[] args) {
        Student student = new Student("Alice", 20, "S12345", "Computer Science");
        System.out.println("---");
        student.introduce();
    }
}

